def count_substrings_with_equal_ends(s):
    count = 0
    n = len(s)
    for i in range(n):
        for j in range(i, n):
            if s[i] == s[j]:
                count += 1
    return count

# Test cases
assert count_substrings_with_equal_ends('abc') == 3
assert count_substrings_with_equal_ends('abcda') == 6
assert count_substrings_with_equal_ends('ab') == 2
